    color: #e6a817;
}
.search-nav-stories:hover{
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
}
.search-nav-following{
    border: 1.5px solid rgba(234, 179, 56, 0.35);
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
    color: #e6a817;
}
.search-nav-following:hover{
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
}
.search-nav-active{
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.30), rgba(255, 204, 51, 0.22));
    box-shadow: 0 0 12px rgba(234, 179, 56, 0.2);
    border-color: rgba(234, 179, 56, 0.55);
}
.search-mode-pill{
    display: flex;
    align-items: center;
    border-radius: 8px;
    border: 1.5px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--text-faint);
    font-family: var(--font-ui);
    font-size: 0.65rem;
    font-weight: 650;
    letter-spacing: 0.04rem;
    text-transform: uppercase;
    padding: 0.35rem 0.6rem;
    white-space: nowrap;
}
.search-gallery-hint{
    margin: 0 0.75rem 0.45rem 0.75rem;
    width: fit-content;
    border: 1.5px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--accent-sage);
    border-radius: 8px;
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 600;
    letter-spacing: 0.01rem;
    padding: 0.34rem 0.62rem;
    cursor: pointer;
    transition: background 0.2s ease, border-color 0.2s ease;
}
.search-gallery-hint:hover{
    background: var(--bg-hover);
    border-color: var(--accent-sage);
}
.search-empty-state{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    padding: 2rem 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.84rem;
    font-weight: 500;
    color: var(--text-faint);
    letter-spacing: 0.01rem;
}
.search-empty-state.is-canvas-only{
    flex-wrap: wrap;
    gap: 0.28rem;
}
.search-empty-link{
    border: none;
    background: transparent;
    color: var(--accent-sage);
    font-family: var(--font-ui);
    font-size: 0.84rem;
    font-weight: 650;
    cursor: pointer;
    text-decoration: underline;
}
.search-empty-link:hover{
    opacity: 0.88;
}
.search-suggestions-dropdown{
    position: absolute;
    left: 0.75rem;
    right: 0.75rem;
    top: calc(100% - 0.15rem);
    z-index: 30;
    border: 1.5px solid var(--border-card);
    border-radius: 10px;
    background: var(--bg-elevated);
    box-shadow:
        0 8px 24px rgba(0, 0, 0, 0.1),
        0 2px 8px rgba(0, 0, 0, 0.06);
    max-height: 320px;
    overflow-y: auto;
    padding: 0.3rem 0;
    animation: searchDropdownIn 0.2s ease-out;
}
@keyframes searchDropdownIn{
    from{
        opacity: 0;
        transform: translateY(-6px);
    }
    to{
        opacity: 1;
        transform: translateY(0);
    }
}
.search-suggestion-item{
    width: 100%;
    text-align: left;
    border: none;
    background: transparent;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    padding: 0.6rem 0.85rem;
    transition: background 0.15s ease;
    border-left: 2.5px solid transparent;
}
.search-suggestion-item:hover{
    background: var(--bg-pill);
    border-left-color: #D4A853;
}
.search-suggestion-title{
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--text-heading);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.search-suggestion-meta{
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 450;
    color: var(--text-faint);
    letter-spacing: 0.01rem;
}
.search-suggestion-muted{
    color: var(--text-faint);
    cursor: default;
    border-left-color: transparent !important;
}
.postcards-parent-container{
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 100%;
    margin-bottom: 1rem;
    gap: 16px;
    padding: 0 16px;
    box-sizing: border-box;
}
.postcards-parent-loading-container{
    position: relative;
    top: 90px;
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
    width: 100%;
    height: 100vh;
}
.loading-newsfeed-bg{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    height: 100%;
}
.jounral-view-image{
    width: 400px;
    height: auto;
}
.inview{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    min-height: 35px;
}

/* ── Card ── */
.cards{
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: center;
    width: 99%;
    max-width: 100%;
    min-height: fit-content;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    overflow: visible;
    cursor: pointer;
    transition: box-shadow 0.25s ease, transform 0.25s ease;
}
.cards:hover{
    box-shadow: 0 6px 24px rgba(80, 60, 40, 0.07);
    transform: translateY(-2px);
}

.bookmarked-content-message-container{
    position: absolute;
    top: 100px;
    background-color: rgb(72, 208, 135);
    color: rgb(255, 255, 255);
    font-size: 0.78rem;
    font-weight: 600;
    padding: 0.45rem 1rem;
    border-radius: 8px;
    width: fit-content;
    z-index: 11;
    transition: ease-in-out 0.2s;
}

/* ── Banner image ── */
.card-image-banner{
    width: 100%;
    max-height: 220px;
    object-fit: cover;
    display: block;
    border-bottom: 1px solid var(--border-card);
    border-radius: 12px 12px 0 0;
    transition: opacity 0.2s ease;
}
.cards:hover .card-image-banner{
    opacity: 0.95;
}

/* ── Card content area ── */
.card-content{
    display: flex;
    flex-direction: column;
    gap: 0.8rem;
    width: 100%;
    padding: 1rem 1.15rem 0.6rem 1.15rem;
    box-sizing: border-box;
}

/* ── User info row ── */
.user-info{
    display: flex;
    justify-content: space-between;
    align-items: center;
}
.user-info-child-container{
    display: flex;
    align-items: center;
    height: 100%;
    gap: 0.4rem;
    width: fit-content;
}
.user-avatar-container{
    display: flex;
    align-items: center;
    justify-content: center;
    width: fit-content;
    height: fit-content;
    cursor: pointer;
}
.user-info-avatar{
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.user-avatar-container.avatar-ring-legend{
    border-radius: 50%;
    border: 2px solid #FFD700;
    box-shadow:
        0 0 6px 1px rgba(255, 215, 0, 0.5),
        0 0 12px 2px rgba(255, 215, 0, 0.35),
        0 0 20px 4px rgba(255, 215, 0, 0.2);
    animation: glow-legend 2s ease-in-out infinite alternate;
}
.user-avatar-container.avatar-ring-og{
    border-radius: 50%;
    border: 2px solid #9B59FF;
    box-shadow:
        0 0 6px 1px rgba(155, 89, 255, 0.5),
        0 0 12px 2px rgba(155, 89, 255, 0.35),
        0 0 20px 4px rgba(155, 89, 255, 0.2);
    animation: glow-og 2s ease-in-out infinite alternate;
}

@keyframes glow-legend {
    from {
        box-shadow:
            0 0 6px 1px rgba(255, 215, 0, 0.5),
            0 0 12px 2px rgba(255, 215, 0, 0.35),
            0 0 20px 4px rgba(255, 215, 0, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(255, 215, 0, 0.6),
            0 0 16px 4px rgba(255, 215, 0, 0.4),
            0 0 24px 6px rgba(255, 215, 0, 0.25);
    }
}

@keyframes glow-og {
    from {
        box-shadow:
            0 0 6px 1px rgba(155, 89, 255, 0.5),
            0 0 12px 2px rgba(155, 89, 255, 0.35),
            0 0 20px 4px rgba(155, 89, 255, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(155, 89, 255, 0.6),
            0 0 16px 4px rgba(155, 89, 255, 0.4),
            0 0 24px 6px rgba(155, 89, 255, 0.25);
    }
}
.user-name-container{
    display: flex;
    align-items: center;
    gap: 0.2rem;
}
.user-newsfeed-name{
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    letter-spacing: 0.005rem;
    margin: 0;
    padding: 0;
    cursor: pointer;
    color: var(--text-secondary);
    transition: color 0.15s ease;
}
.user-newsfeed-name:hover{
    text-decoration: underline;
    color: var(--accent-sage);
}
.name-info-separator{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    color: var(--text-separator);
    font-size: 0.4rem;
    user-select: none;
}
.user-info-email-container{
    display: none;
}
.user-info-email{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 400;
    color: var(--text-faint);
}
.user-post-date-container{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    cursor: default;
    user-select: none;
}
.user-post-privacy{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    cursor: default;
    user-select: none;
    color: var(--text-heading);
}
.user-post-date{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 400;
    color: var(--text-faint);
}
.user-post-settings{
    position: relative;
    display: flex;
    flex-direction: column;
    justify-self: flex-end;
    width: fit-content;
    height: fit-content;
    cursor: pointer;
    user-select: none;
    color: var(--text-heading);
}
.setting-modal{
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    right: 25px;
    bottom: 10px;
    width: 200px;
    height: 100px;
    border-radius: 10px;
    z-index: 200;
    background-color: var(--bg-elevated);
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
    border: 1px solid var(--border-card);
}

/* ── Content (title + text) ── */
.content-container{
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    user-select: none;
    gap: 0.5rem;
}
.feed-text-content-container{
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    justify-content: flex-start;
    align-items: flex-start;
    gap: 0.35rem;
}
.feed-title-content{
    display: flex;
    justify-content: center;
    align-items: center;
}
.cards.is-canvas-card .feed-title-content{
    flex-direction: row;
    justify-content: flex-start;
    gap: 0.45rem;
}
.feed-title{
    margin: 0;
    padding: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.1rem;
    font-weight: 700;
    line-height: 1.45;
    letter-spacing: -0.025rem;
    color: var(--text-heading);
}
.feed-text-content{
    padding: 0;
    margin: 0;
    font-family: var(--font-serif);
    font-weight: 400;
    color: var(--text-body);
    line-height: 1.7;
    font-size: 0.88rem;
    letter-spacing: 0.005rem;
}

.canvas-card-actions{
    display: flex;
    flex-wrap: wrap;
    gap: 0.42rem;
    width: 100%;
    margin-top: -0.1rem;
}

.canvas-card-action-btn{
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--text-secondary);
    border-radius: 999px;
    padding: 0.3rem 0.65rem;
    font-size: 0.68rem;
    font-weight: 620;
    cursor: pointer;
    transition: border-color 0.2s ease, background 0.2s ease, color 0.2s ease;
}

.canvas-card-action-btn:hover{
    border-color: var(--accent-sage);
    color: var(--accent-sage);
}

.canvas-card-action-btn.is-remix{
    border-color: color-mix(in srgb, var(--accent-purple) 42%, var(--border-card));
    color: var(--accent-purple);
}

/* ── Icon bar ── */
.card-icons-container{
    display: flex;
    flex-wrap: wrap;
    width: 100%;
    padding: 0.5rem 1.15rem 0.85rem 1.15rem;
    min-height: 22px;
    align-items: center;
    justify-content: flex-start;
    gap: 0.5rem;
    box-sizing: border-box;
    border-top: 1px solid var(--border-card);
}
#card-icons{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.35rem;
    border-radius: 50%;
    transition: background-color 0.2s ease;
    gap: 0.3rem;
}
#card-icons-view{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.1rem;
    border-radius: 50%;
    transition: background-color 0.2s ease;
    gap: 0.3rem;
}
.card-icons{
    display: flex;
    width: fit-content;
    height: fit-content;
    justify-content: center;
    align-items: center;
}
.icon-container{
    display: flex;
    justify-content: center;
    align-items: center;
}
.icon-container p{
    font-family: var(--font-ui);
}

.like-button:hover .svg-like path{
    fill: rgb(255, 116, 116);
}
.like-button:hover{
    background-color: rgba(255, 161, 161, 0.12);
}
.comment-button:hover{
    background-color: rgba(212, 168, 83, 0.12);
}
.comment-button:hover .svg-comment path{
    fill: var(--accent-amber);
}
.bookmark-button:hover{
    background-color: rgba(245, 158, 11, 0.12);
}
.bookmark-button:hover .svg-bookmark path{
    fill: var(--accent-amber);
}

/* ── Reading time pill ── */
.reading-time-container{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.2rem 0.7rem;
    background-color: var(--bg-pill);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    margin-left: auto;
}
.reading-time-text{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.62rem;
    font-weight: 550;
    color: var(--accent-sage);
    letter-spacing: 0.01rem;
}

/* ── Repost card ── */
.repost-header-badge{
    display: flex;
    align-items: center;
    gap: 0.35rem;
    padding: 0.5rem 1.15rem 0;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-faint);
}
.repost-header-name{
    font-weight: 650;
    color: var(--text-secondary);
    cursor: pointer;
}
.repost-header-name:hover{
    text-decoration: underline;
    color: var(--accent-sage);
}
.repost-caption-text{
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 450;
    color: var(--text-heading);
    line-height: 1.6;
    white-space: pre-wrap;
    word-break: break-word;
}
.repost-embedded-card{
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    padding: 0.75rem;
    background: var(--bg-secondary);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    cursor: pointer;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
}
.repost-embedded-card:hover{
    border-color: var(--accent-sage);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.06);
}
.repost-embedded-author{
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.repost-embedded-avatar{
    width: 18px;
    height: 18px;
    border-radius: 50%;
    object-fit: cover;
}
.repost-embedded-name{
    font-family: var(--font-ui);
    font-size: 0.74rem;
    font-weight: 600;
    color: var(--text-secondary);
}
.repost-embedded-title{
    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 0.92rem;
    font-weight: 650;
    color: var(--text-heading);
    line-height: 1.35;
}
.repost-embedded-text{
    margin: 0;
    font-family: var(--font-serif);
    font-size: 0.8rem;
    font-weight: 400;
    color: var(--text-body);
    line-height: 1.55;
}
.repost-unavailable{
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1.5rem;
    background: var(--bg-secondary);
    border: 1px dashed var(--border-card);
    border-radius: 10px;
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 500;
    color: var(--text-faint);
}
.repost-button:hover{
    background-color: rgba(72, 208, 135, 0.12);
}
.repost-button:hover .svg-repost path{
    fill: var(--accent-sage);
}
.repost-toast{
    position: fixed;
    bottom: 2rem;
    left: 50%;
    transform: translateX(-50%);
    z-index: 1000;
    padding: 0.5rem 1.2rem;
    background: var(--accent-sage);
    color: #fff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    border-radius: 8px;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
}

.sample-content-show{
    width: 100%;
    height: 100%;
    background-color: var(--bg-primary);
    z-index: 10;
}

/* ── Mobile responsive ── */
@media (max-width: 480px){

    /* ── Mobile top header ── */
    .mobile-top-header{
        display: flex;
        align-items: center;
        justify-content: space-between;
        position: sticky;
        top: 0;
        z-index: 122;
        width: 100%;
        padding: 0.65rem 0.75rem;
        box-sizing: border-box;
        background: var(--bg-primary);
        border-bottom: 1px solid var(--border-card);
    }
    .mobile-brand-text{
        font-family: 'Playfair Display', serif;
        font-size: 1.4rem;
        font-weight: 700;
        color: var(--text-heading);
        letter-spacing: -0.02rem;
    }
    .mobile-header-profile-btn{
        display: flex;
        align-items: center;
        justify-content: center;
        background: none;
        border: 1.5px solid var(--border-card);
        border-radius: 50%;
        padding: 0;
        cursor: pointer;
        -webkit-tap-highlight-color: transparent;
        transition: border-color 0.2s ease;
    }
    .mobile-header-profile-btn:active{
        border-color: #D4A853;
    }
    .mobile-header-profile-btn img{
        width: 30px;
        height: 30px;
        border-radius: 50%;
        object-fit: cover;
    }

    /* ── Search bar visible on mobile ── */
    .search-shell{
        top: 0;
        position: relative;
    }
    .search-top-bar{
        padding: 0.5rem 0.5rem 0.55rem 0.5rem;
        gap: 0.4rem;
    }
    .search-input{
        font-size: 0.8rem;
        padding: 0.5rem 0.75rem 0.5rem 2.1rem;
        border-radius: 8px;
    }
    .search-icon{
        left: 0.7rem;
        width: 14px;
        height: 14px;
    }
    .search-clear-btn{
        font-size: 0.64rem;
        padding: 0.32rem 0.52rem;
        border-radius: 6px;
    }
    .search-nav-row{
        padding: 0.35rem 0.5rem;
        gap: 5px;
    }
    .search-nav-btn{
        font-size: 0.68rem;
        padding: 0.42rem 0.5rem;
    }
    .search-mode-pill{
        font-size: 0.58rem;
        padding: 0.28rem 0.44rem;
        border-radius: 6px;
    }
    .search-gallery-hint{
        margin: 0 0.5rem 0.42rem 0.5rem;
        font-size: 0.6rem;
        padding: 0.3rem 0.5rem;
        border-radius: 6px;
    }
    .search-suggestions-dropdown{
        left: 0.5rem;
        right: 0.5rem;
        top: calc(100% - 0.1rem);
        max-height: 260px;
        border-radius: 8px;
    }
    .search-suggestion-item{
        padding: 0.52rem 0.7rem;
        border-left-width: 2px;
    }
    .search-suggestion-title{
        font-size: 0.76rem;
    }
    .search-suggestion-meta{
        font-size: 0.62rem;
    }

    /* ── Inline Write button (mobile only) ── */
    .mobile-write-btn{
        display: flex;
        align-items: center;
        gap: 0.3rem;
        border: 1.5px solid rgba(212, 168, 83, 0.4);
        background: linear-gradient(135deg, rgba(212, 168, 83, 0.15), rgba(212, 168, 83, 0.08));
        color: #D4A853;
        border-radius: 8px;
        font-family: var(--font-ui);
        font-size: 0.68rem;
        font-weight: 700;
        letter-spacing: 0.01rem;
        padding: 0.38rem 0.6rem;
        cursor: pointer;
        white-space: nowrap;
        -webkit-tap-highlight-color: transparent;
        transition: background 0.15s ease, transform 0.15s ease;
    }
    .mobile-write-btn:active{
        transform: scale(0.96);
    }
    .mobile-write-btn svg{
        flex-shrink: 0;
    }


    .postcards-parent-container {
        position: relative;
        top: 0;
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 100%;
        margin-top: 0.5rem;
        margin-bottom: 1rem;
        gap: 12px;
        padding: 0 10px;
        box-sizing: border-box;
    }
    .postcards-parent-loading-container {
        position: relative;
        top: 60px;
        display: flex;
        justify-content: center;
        align-items: center;
        flex-direction: column;
        width: 100%;
        height: 100vh;
    }
    .cards{
        border-radius: 10px;
        overflow: visible;
        max-width: 100%;
        box-sizing: border-box;
    }
    .card-image-banner{
        max-height: 220px;
        border-radius: 10px 10px 0 0;
    }
    .card-content{
        width: 100%;
        padding: 0.75rem 0.75rem 0.4rem 0.75rem;
        box-sizing: border-box;
    }
    .content-container {
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: flex-start;
        user-select: none;
        gap: 0.3rem;
    }
    .feed-title{
        font-size: 0.92rem;
        line-height: 1.3;
    }
    .feed-text-content {
        padding: 0;
        margin: 0;
        font-family: var(--font-serif);
        font-weight: 400;
        font-size: 0.78rem;
        color: var(--text-body);
        line-height: 1.5;
    }
    .canvas-card-actions{
        gap: 0.34rem;
    }
    .canvas-card-action-btn{
        font-size: 0.64rem;
        padding: 0.26rem 0.55rem;
    }

    /* Footer: two explicit rows — author top, actions bottom */
    .card-icons-container{
        display: flex;
        flex-wrap: wrap;
        width: 100%;
        padding: 0.5rem 0.75rem 0.7rem 0.75rem;
        min-height: auto;
        height: auto;
        align-items: center;
        justify-content: flex-start;
        gap: 0.4rem;
        row-gap: 0.5rem;
        box-sizing: border-box;
        overflow: visible;
    }

    /* Row 1: Author info — full width, forces wrap */
    .card-icons-container .user-info-child-container{
        display: flex;
        align-items: center;
        flex: 0 0 100%;
        gap: 0.3rem;
        padding-bottom: 0.25rem;
        border-bottom: 0.5px solid var(--border-card);
        margin-bottom: 0.1rem;
    }
    .card-icons-container .user-info-child-container .user-newsfeed-name{
        font-family: var(--font-ui);
        font-size: 0.72rem;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
        max-width: 120px;
    }
    .card-icons-container .user-info-child-container .user-post-date{
        font-family: var(--font-ui);
        font-size: 0.6rem;
        white-space: nowrap;
    }
    .card-icons-container .user-info-child-container .user-info-avatar{
        width: 20px;
        height: 20px;
    }

    /* Row 2: Action icons — guaranteed visible */
    .icon-container{
        display: flex !important;
        align-items: center;
        flex-shrink: 1;
        min-width: 0;
        min-height: 24px;
        visibility: visible;
    }

    /* Base icon button styles (covers like, comment, bookmark) */
    .icon-container .like-button,
    .icon-container .comment-button,
    .icon-container .bookmark-button{
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.3rem;
        border-radius: 50%;
        transition: background-color 0.2s ease;
    }

    .svg-like{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    .svg-comment{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    .svg-bookmark{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    #card-icons{
        display: flex;
        align-items: center;
        padding: 0.3rem;
        gap: 0.15rem;
    }
    #card-icons-view{
        display: flex;
        align-items: center;
    }
    #card-icons-view svg{
        width: 22px;
        height: 22px;
    }
    .icon-container p{
        font-family: var(--font-ui);
        font-size: 0.68rem !important;
        white-space: nowrap;
        margin: 0 !important;
        padding: 0 !important;
    }

    /* Reading time pill — always visible, pushed right */
    .reading-time-container{
        display: flex !important;
        visibility: visible;
        margin-left: auto;
        padding: 0.2rem 0.6rem;
        flex-shrink: 0;
        min-width: fit-content;
    }
    .reading-time-text{
        font-size: 0.58rem;
        white-space: nowrap;
    }

    .user-post-settings{
        flex-shrink: 0;
        color: var(--text-heading);
    }
    .user-post-settings svg{
        width: 20px;
        height: 20px;
    }
    .setting-modal{
        right: 0;
        bottom: 25px;
        width: 180px;
        height: 80px;
        font-size: 0.75rem;
    }
    .toolbar {
        display: flex;
        justify-content: center;
        height: 100%;
        width: 100%;
    }
    .toolbar-bttns {
        display: flex;
        width: 16px;
        height: 16px;
        justify-content: center;
        align-items: center;
        padding: 0.5rem;
        border-radius: 10px;
        cursor: pointer;
        transition: ease-in-out 0.1s;
        user-select: none;
    }
    .editor-save-bttn {
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.2rem 0.8rem;
        font-size: 0.8rem;
        border-radius: 15px;
        margin-right: 1rem;
        background-color: rgb(255, 255, 255);
        color: rgb(4, 20, 29);
        font-weight: 600;
        cursor: pointer;
        border: hidden;
    }

}

export const SITE_NAME = "Iskryb";
export const SITE_URL = "https://iskrib.com";
export const DEFAULT_OG_IMAGE = `${SITE_URL}/assets/og-banner.png`;
export const DEFAULT_OG_IMAGE_WIDTH = 1200;
export const DEFAULT_OG_IMAGE_HEIGHT = 630;

export const DEFAULT_SEO = {
  title: `${SITE_NAME} | Social Journaling and Opinions`,
  description:
    "Iskryb is a social journaling platform where you can publish journals, share opinions, and organize collections.",
  canonicalPath: "/",
  robots: "index,follow",
};

export const SEO_ROUTES = [
  {
    path: "/",
    title: `${SITE_NAME} | Social Journaling and Opinions`,
    description:
      "Publish journals, share opinions, and build collections in one social writing platform.",
    canonicalPath: "/",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "1.0" },
  },
  {
    path: "/home",
    title: `${SITE_NAME} Home Feed`,
    description:
      "Explore journals and ideas from the Iskryb community in the home feed.",
    canonicalPath: "/home",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.9" },
  },
  {
    path: "/home/opinions",
    title: `${SITE_NAME} Opinions`,
    description:
      "Read and respond to community opinions on Iskryb with threaded discussions.",
    canonicalPath: "/home/opinions",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.8" },
  },
  {
    path: "/home/explore",
    title: `${SITE_NAME} Explore`,
    description:
      "Discover the hottest posts and search across community journals on Iskryb.",
    canonicalPath: "/home/explore",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.8" },
  },
  {
    path: "/home/gallery",
    title: `${SITE_NAME} Gallery`,
    description:
      "Browse visual canvas posts in Iskryb Gallery with community doodles, stamps, and remixes.",
    canonicalPath: "/home/gallery",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.8" },
  },
  {
    path: "/home/freedom-wall",
    title: `${SITE_NAME} Freedom Wall`,
    description:
      "Join the live weekly Freedom Wall to doodle, drop stickers and stamps, and leave colorful notes with the community.",
    canonicalPath: "/home/freedom-wall",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.8" },
  },
  {
    path: "/login",
    title: `Log In | ${SITE_NAME}`,
    description: `Log in to ${SITE_NAME} to continue writing and engaging with the community.`,
    canonicalPath: "/login",
    robots: "noindex,follow",
    prerender: true,
  },
  {
    path: "/signUp",
    title: `Sign Up | ${SITE_NAME}`,
    description:
      "Create an Iskryb account to publish journals, share opinions, and curate collections.",
    canonicalPath: "/signUp",
    robots: "noindex,follow",
    prerender: true,
  },
];

const DYNAMIC_PATTERNS = [
  {
    test: (pathname) => /^\/home\/post\/[^/]+(?:\/[^/]+)?$/.test(pathname),
    seo: (pathname) => {
      const match = pathname.match(/^\/home\/post\/([^/]+)/);
      const journalId = match ? match[1] : null;
      return {
        title: `${SITE_NAME} Post`,
        description: "Read community journals and discussions on Iskryb.",
        canonicalPath: journalId ? `/home/post/${journalId}` : null,
        robots: "index,follow",
      };
    },
  },
  {
    test: (pathname) => /^\/u\/[^/]+/.test(pathname),
    seo: (pathname) => {
      const username = pathname.split("/")[2];
      return {
        title: `${username}'s Profile | ${SITE_NAME}`,
        description: `View ${username}'s journals and opinions on Iskryb.`,
        canonicalPath: `/u/${username}`,
        robots: "index,follow",
      };
    },
  },
];

export const buildAbsoluteUrl = (pathOrUrl = "/") => {
  if (!pathOrUrl) {
    return `${SITE_URL}/`;
  }

  if (/^https?:\/\//i.test(pathOrUrl)) {
    return pathOrUrl;
  }

  return new URL(pathOrUrl, `${SITE_URL}/`).toString();
};

export const getSeoForPath = (pathname) => {
  const normalized = pathname || "/";
  const exactMatch = SEO_ROUTES.find((route) => route.path === normalized);
  if (exactMatch) {
    return { ...DEFAULT_SEO, ...exactMatch };
  }

  const dynamicMatch = DYNAMIC_PATTERNS.find((entry) => entry.test(normalized));
  if (dynamicMatch) {
    const seo = typeof dynamicMatch.seo === "function"
      ? dynamicMatch.seo(normalized)
      : dynamicMatch.seo;
    return { ...DEFAULT_SEO, ...seo };
  }

  return { ...DEFAULT_SEO };
};

export const getPrerenderRoutes = () =>
  SEO_ROUTES.filter((route) => route.prerender).map((route) => route.path);

export const getSitemapRoutes = () =>
  SEO_ROUTES.filter((route) => route.sitemap).map((route) => ({
    path: route.path,
    ...route.sitemap,
  }));

export const buildWebsiteSchema = (canonicalUrl) => ({
  "@context": "https://schema.org",
  "@type": "WebSite",
  name: SITE_NAME,
  url: canonicalUrl,
});

export const ORGANIZATION_SCHEMA = {
  "@context": "https://schema.org",
  "@type": "Organization",
  name: SITE_NAME,
  url: `${SITE_URL}/`,
  logo: DEFAULT_OG_IMAGE,
};

import { useEffect, useRef, useState } from 'react';
import './mobilenavlink.css';
import { motion } from 'framer-motion';
import { useAuth } from '../../Context/useAuth';
import { useLocation, useNavigate } from 'react-router-dom';

const MobileNavlink = () => {
    const [showNavlinks, setShowNavlinks] = useState(true);
    const timeOutRef = useRef();
    const navigate = useNavigate();
    const location = useLocation();

    const { session, openAuthModal } = useAuth();

    const handleNavigatePath = (path) => {
        if (location.pathname === path) {
            return window.location.reload();
        }
        return navigate(path);
    };

    const activeColor = '#D4A853';
    const inactiveColor = '#787878';

    const navLinks = [
        {
            type: 'icon',
            label: 'Home',
            path: '/home',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
                    <g clipPath="url(#clip0_1_110)">
                        <path fillRule="evenodd" clipRule="evenodd" d="M14.3594 2.12613C13.0087 0.944612 10.9923 0.94461 9.64162 2.12612L3.2802 7.69086C2.29508 8.55261 1.72998 9.79772 1.72998 11.1066L1.72998 19.1672C1.72998 21.1459 3.33403 22.75 5.31273 22.75L18.6883 22.75C20.667 22.75 22.271 21.1459 22.271 19.1672L22.271 11.1066C22.271 9.79772 21.706 8.55261 20.7208 7.69086L14.3594 2.12613ZM10 16.1136C9.58579 16.1136 9.25 16.4494 9.25 16.8636C9.25 17.2779 9.58579 17.6136 10 17.6136L14 17.6136C14.4142 17.6136 14.75 17.2779 14.75 16.8636C14.75 16.4494 14.4142 16.1136 14 16.1136L10 16.1136Z" fill={isActive ? activeColor : inactiveColor}/>
                    </g>
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Explore',
            path: '/home/explore',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
                    <path
                        fillRule="evenodd"
                        d="M12,2 C17.5228475,2 22,6.4771525 22,12 C22,17.5228475 17.5228475,22 12,22 C6.4771525,22 2,17.5228475 2,12 C2,6.4771525 6.4771525,2 12,2 Z M17.9842695,7.39078625 C18.1985588,6.64477525 17.4973604,5.9435768 16.7513494,6.1578661 L16.6494246,6.19284365 L9.57835679,9.02127078 L9.47282273,9.07079854 C9.30957453,9.15937167 9.17428758,9.29167162 9.08209683,9.45256344 L9.02127078,9.57835679 L6.19284365,16.6494246 L6.1578661,16.7513494 C5.9435768,17.4973604 6.64477525,18.1985588 7.39078625,17.9842695 L7.49271102,17.949292 L14.5637788,15.1208648 L14.6693129,15.0713371 C14.8325611,14.982764 14.967848,14.850464 15.0600388,14.6895722 L15.1208648,14.5637788 L17.949292,7.49271102 L17.9842695,7.39078625 Z M12,10 C13.1045695,10 14,10.8954305 14,12 C14,13.1045695 13.1045695,14 12,14 C10.8954305,14 10,13.1045695 10,12 C10,10.8954305 10.8954305,10 12,10 Z"
                    />
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Gallery',
            path: '/home/gallery',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill={isActive ? activeColor : inactiveColor}>
                    <path d="M480-80q-83 0-156-31.5T197-197q-54-54-85.5-127T80-480q0-83 31.5-156T197-763q54-54 127-85.5T480-880q63 0 121.5 18.5T709-807q-17 19-26 44t-9 52q0 53 37.5 90.5T802-583q27 0 52-9t44-26q36 49 54 107.5T970-480q0 83-31.5 156T853-197q-54 54-127 85.5T570-80H480Zm-12-196q30 0 51-21t21-51q0-30-21-51t-51-21q-30 0-51 21t-21 51q0 30 21 51t51 21Zm-153-84q24 0 42-18t18-42q0-24-18-42t-42-18q-24 0-42 18t-18 42q0 24 18 42t42 18Zm6-189q17 0 28.5-11.5T361-589q0-17-11.5-28.5T321-629q-17 0-28.5 11.5T281-589q0 17 11.5 28.5T321-549Zm183-66q36 0 60-24t24-60q0-36-24-60t-60-24q-36 0-60 24t-24 60q0 36 24 60t60 24Z"/>
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Freedom Wall',
            path: '/home/freedom-wall',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill="none">
                    <path d="M4 7.2A3.2 3.2 0 0 1 7.2 4h9.6A3.2 3.2 0 0 1 20 7.2v9.6a3.2 3.2 0 0 1-3.2 3.2H7.2A3.2 3.2 0 0 1 4 16.8V7.2Z" stroke={isActive ? activeColor : inactiveColor} strokeWidth="1.6" />
                    <path d="M8 15.5c1.7-3 2.4-3 4 0 1.5-2.2 2.1-2.2 3.9 0" stroke={isActive ? activeColor : inactiveColor} strokeWidth="1.6" strokeLinecap="round" />
                    <circle cx="9" cy="9.2" r="1.1" fill={isActive ? activeColor : inactiveColor} />
                    <circle cx="14.2" cy="8.6" r="0.9" fill={isActive ? activeColor : inactiveColor} />
                </svg>
            ),
        },
        {
            type: 'icon',
            label: 'Universe',
            path: '/universe',
            action: (path) => handleNavigatePath(path),
            icon: (isActive) => (
                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
                    <circle cx="6" cy="6" r="2"/>
                    <circle cx="18" cy="8" r="1.5"/>
                    <circle cx="12" cy="4" r="1"/>
                    <circle cx="10" cy="14" r="2.5"/>
                    <circle cx="17" cy="17" r="1.8"/>
                    <circle cx="5" cy="19" r="1.2"/>
                    <line x1="6" y1="6" x2="12" y2="4" stroke={isActive ? activeColor : inactiveColor} strokeWidth="0.5" opacity="0.4"/>
                    <line x1="12" y1="4" x2="18" y2="8" stroke={isActive ? activeColor : inactiveColor} strokeWidth="0.5" opacity="0.4"/>
                    <line x1="6" y1="6" x2="10" y2="14" stroke={isActive ? activeColor : inactiveColor} strokeWidth="0.5" opacity="0.4"/>
                    <line x1="10" y1="14" x2="17" y2="17" stroke={isActive ? activeColor : inactiveColor} strokeWidth="0.5" opacity="0.4"/>
                </svg>
            ),
        },
    ];

    useEffect(() => {
        const scroll = () => {
            setShowNavlinks(false);

            if (timeOutRef.current) {
                clearTimeout(timeOutRef.current);
            }

            timeOutRef.current = setTimeout(() => {
                setShowNavlinks(true);
            }, 500);
        };

        document.addEventListener('scroll', scroll, true);
        return () => {
            if (timeOutRef.current) {
                clearTimeout(timeOutRef.current);
            }
            document.removeEventListener('scroll', scroll, true);
        };
    }, []);

    return (
        <>
            {showNavlinks && (
                <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 25, mass: 0.8 } }}
                    exit={{ opacity: 0, y: 20, transition: { duration: 0.2, ease: 'easeOut' } }}
                    className="mobile-navlink-container"
                >
                    <div className="mobile-navlink-icon-container">
                        {navLinks.map((link, index) => {
                            const isActive = link.path && location.pathname === link.path;

                            return (
                                <div
                                    key={index}
                                    className="mobile-navlink-item"
                                    onClick={() => link.action(link.path)}
                                >
                                    <div className="mobile-navlink-icons">
                                        {link.icon(isActive)}
                                    </div>
                                    <p className={`mobile-navlink-label ${isActive ? 'mobile-navlink-label-active' : ''}`}>
                                        {link.label}
                                    </p>
                                    {isActive && <div className="mobile-navlink-active-dot" />}
                                </div>
                            );
                        })}
                    </div>
                </motion.div>
            )}
        </>
    );
};

export default MobileNavlink;

